        if order.region == "blocked-region":
            raise ShipmentPlanningError("Shipment carrier unavailable for region.")
        return Shipment(
            id=new_identifier("shipment"),
            order_id=order.id,
            warehouse_id=warehouse_id,
            carrier=carrier,
            tracking_code=f"trk-{order.id[-6:]}-{warehouse_id[-3:]}",
            status="queued",
        )


